import React from 'react';
import { View, Text } from 'react-native';
import { NavigationEvents, withNavigationFocus } from "react-navigation";
import AsyncStorage from "@react-native-async-storage/async-storage"

class DebugModule extends React.Component {
  componentDidMount() {
    this.props.navigation.addListener('didFocus', payload => {
      console.debug(`Screen focused: ${payload}`); // Log screen focus event
      
      AsyncStorage.getAllKeys().then((keys) => {
        keys.map((key, index) => {
          AsyncStorage.getItem(key).then((value) => {
            console.debug('AsyncStorage:', key, value); // Log all items in AsyncStorage 
          });
        });  
      });
    });
    
    this.willFocusSubscription = this.props.navigation.addListener(
      'willFocus',
      payload => {
        console.debug('Screen will focus: ', payload); // Log screen will focus event
      }
    ); 
  }
  
  componentWillUnmount() {
    this.willFocusSubscription.remove();
  }

  render(){
    return (<View><Text>DebugModule View</Text></View>); // Replace this with your actual view components
  }
}

export default withNavigationFocus(DebugModule);